module RefModule(
	input clk,
	input enable,
	input load,
	input reset,
	input [11:0] load_val,
	output reg [11:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (reset)
		q <= 12'b000000000000;
	else if (load)
		q <= load_val;
	else if (enable)
		q <= q + 1;
end
endmodule
